import { NavLink } from "react-router-dom";
import { useAuth, hasRole } from "../AuthContext";

const linkCls =
    ({ isActive }) =>
        "px-3 py-2 rounded-md text-sm block " +
        (isActive ? "bg-indigo-600 text-white" : "hover:bg-indigo-100");

export default function Sidebar() {
    const { user } = useAuth();
    const isAdmin = hasRole(user, "ADMIN");
    const isSales = hasRole(user, "SALES");
    const isAccountant = hasRole(user, "ACCOUNTANT");

    return (
        <aside className="w-64 bg-white h-screen border-r border-slate-200">
            <div className="p-4 border-b">
                <div className="w-10 h-10 rounded-xl bg-indigo-600 text-white grid place-content-center font-bold">CT</div>
                <div className="mt-2 font-bold">Quản lý KH & HĐ</div>
                <div className="text-xs text-slate-500">Bản React</div>
            </div>

            <nav className="p-3 flex flex-col gap-1">
                <NavLink to="/dashboard" className={linkCls}>📊 Tổng quan</NavLink>

                {(isAdmin || isSales) && (
                    <NavLink to="/customers" className={linkCls}>👥 Khách hàng</NavLink>
                )}

                {(isAdmin || isSales) && (
                    <NavLink to="/contracts" className={linkCls}>📑 Hợp đồng</NavLink>
                )}

                {(isAdmin || isAccountant) && (
                    <NavLink to="/payments" className={linkCls}>💰 Thanh toán</NavLink>
                )}

                <NavLink to="/events" className={linkCls}>📅 Sự kiện</NavLink>

                {isAdmin && (
                    <NavLink to="/users" className={linkCls}>🛠 Người dùng</NavLink>
                )}

                <NavLink to="/reports" className={linkCls}>📈 Báo cáo</NavLink>
            </nav>
        </aside>
    );
}
